package com.i2i.voltwise.state;
import com.i2i.voltwise.home.*; import com.i2i.voltwise.home.HomeDtos.*; import org.apache.ignite.client.*; import org.apache.ignite.cache.query.ScanQuery; import org.springframework.stereotype.Service; import java.util.*;
@Service public class LiveStateService { private final ClientCache<UUID,LiveModels.HomeLive> cache; public LiveStateService(IgniteClient ignite){this.cache=ignite.getOrCreateCache("home-live-state");} public void register(Home h){var s=new LiveModels.HomeLive();s.id=h.id;s.name=h.name;s.email=h.email;s.budgetLimit=h.budgetLimit.doubleValue();s.baseTariff=h.baseTariff.doubleValue();s.penaltyMultiplier=h.penaltyMultiplier.doubleValue();h.appliances.forEach(a->s.appliances.put(a.id,new LiveModels.ApplianceLive(a.id,a.name,a.safeWattLimit.doubleValue())));cache.put(s.id,s);} public LiveModels.HomeLive get(UUID id){return cache.get(id);} public void put(LiveModels.HomeLive s){cache.put(s.id,s);} public List<HomeStatus> all(){var list=new ArrayList<HomeStatus>();try(var cursor=cache.query(new ScanQuery<UUID,LiveModels.HomeLive>())){for(var e:cursor)list.add(toDto(e.getValue()));}return list;} public HomeStatus status(UUID id){var s=get(id);if(s==null)throw new NoSuchElementException("Ev bulunamadı");return toDto(s);} private HomeStatus toDto(LiveModels.HomeLive s){var devices=s.appliances.values().stream().map(a->new ApplianceStatus(a.id,a.name,a.watts,a.safeLimit,a.breachCount,a.anomalous)).toList();double pct=s.budgetLimit==0?0:s.cost/s.budgetLimit*100;return new HomeStatus(s.id,s.name,s.email,s.energyKwh,s.cost,s.budgetLimit,pct,s.penalty,pct>=80,devices);} }
